import './index.css';

import {
  useEffect,
  useState
} from 'react';

import Header
from '../../components/common/Header';

import {
  getStudentMarks
} from '../../services/studentMarksService';

function StudentMarks() {

  // ======================================
  // STATES
  // ======================================

  const [marks, setMarks] =
    useState([]);

  const [loading, setLoading] =
    useState(true);

  const [totalMarks, setTotalMarks] =
    useState(0);

  const [average, setAverage] =
    useState(0);

  // ======================================
  // LOAD DATA
  // ======================================

  useEffect(() => {

    loadMarks();

  }, []);

  const loadMarks =
    async () => {

    try {

      const data =
        await getStudentMarks();

      console.log(data);

      setMarks(data);

      // TOTAL

      let total = 0;

      data.forEach((item) => {

        total +=
          Number(
            item.marks_obtained
          );

      });

      setTotalMarks(total);

      // AVERAGE

      if (data.length > 0) {

        setAverage(

          (
            total /
            data.length

          ).toFixed(2)

        );

      }

    } catch (error) {

      console.log(error);

    } finally {

      setLoading(false);

    }

  };

  return (

    <div className="student-marks-page">

      {/* HEADER */}

      <Header />


      {/* CONTENT */}

      <div className="student-marks-content">

        {/* TOP */}

        <div className="marks-top">

          <div>

            <h1>
              My Marks
            </h1>

            <p>
              View academic performance and grades
            </p>

          </div>

        </div>


        {/* SUMMARY */}

        <div className="summary-grid">

          {/* TOTAL */}

          <div className="summary-card">

            <h3>
              Total Marks
            </h3>

            <p>
              {totalMarks}
            </p>

          </div>


          {/* SUBJECT COUNT */}

          <div className="summary-card">

            <h3>
              Subjects
            </h3>

            <p>
              {marks.length}
            </p>

          </div>


          {/* AVERAGE */}

          <div className="summary-card">

            <h3>
              Average
            </h3>

            <p>
              {average}%
            </p>

          </div>

        </div>


        {/* LOADING */}

        {

          loading
          ? (

            <div className="loading-box">

              Loading Marks...

            </div>

          )
          : (

            <div className="marks-grid">

              {

                marks.length > 0
                ? (

                  marks.map((mark) => (

                    <div
                      key={mark.id}
                      className="mark-card"
                    >

                      {/* TOP */}

                      <div className="card-top">

                        <h3>

                          {mark.subject_name}

                        </h3>

                        <span className="grade-badge">

                          {mark.grade}

                        </span>

                      </div>


                      {/* INFO */}

                      <div className="mark-info">

                        <p>

                          <strong>
                            Subject ID:
                          </strong>

                          {' '}

                          {

                            mark.subject_id ||

                            'N/A'

                          }

                        </p>

                        <p>

                          <strong>
                            Assessment ID:
                          </strong>

                          {' '}

                          {

                            mark.assessment_id ||

                            'N/A'

                          }

                        </p>

                        <p>

                          <strong>
                            Marks Obtained:
                          </strong>

                          {' '}

                          {mark.marks_obtained}

                        </p>

                        <p>

                          <strong>
                            Percentage:
                          </strong>

                          {' '}

                          {mark.percentage}%

                        </p>

                      </div>

                    </div>

                  ))

                )
                : (

                  <div className="empty-box">

                    No Marks Available

                  </div>

                )

              }

            </div>

          )

        }

      </div>

    </div>

  );

}

export default StudentMarks;
